args.sparql:
SELECT ?seasonNumber ?winner WHERE {
  wd:Q31426 wdt:P505 ?season .
  ?season wdt:P1852 wd:Q234423 .
  ?season wdt:P5370 ?seasonNumber .
  ?season wdt:P1852 ?winner .
}

SELECT ?winnerLabel WHERE {
  wd:Q2623676 wdt:P1340 ?winner . 
  ?winner rdfs:label ?winnerLabel .
  FILTER(LANG(?winnerLabel) = "en")
}

SELECT ?winnerLabel WHERE {
  wd:Q2623676 wdt:P1852 ?winner .
  ?winner rdfs:label ?winnerLabel .
  FILTER(LANG(?winnerLabel) = "en")
}
